const { google } = require\('googleapis'\);
const fs = require\('fs'\);
const mammoth = require\('mammoth'\);

const key = JSON.parse\(fs.readFileSync\('./service-account.json', 'utf8'\)\);
const auth = new google.auth.GoogleAuth\({ credentials: key, scopes: ['https://www.googleapis.com/auth/drive.readonly'] }\);
const drive = google.drive\({ version: 'v3', auth }\);

async function downloadFile\(fileId\) {
  const res = await drive.files.get\({ fileId, alt: 'media' }, { responseType: 'arraybuffer' }\);
  return Buffer.from\(res.data\);
}

async function main\(\) {
  // Google Doc
  const docRes = await drive.files.export\(
    { fileId: '1PKPtHWXK32L-a5k5QNsqjJC9KkCQub3cd7uxQeiYcTY', mimeType: 'text/plain' },
