const { google } = require\('googleapis'\);
const fs = require\('fs'\);
const key = JSON.parse\(fs.readFileSync\('./service-account.json', 'utf8'\)\);
const auth = new google.auth.GoogleAuth\({ credentials: key, scopes: ['https://www.googleapis.com/auth/drive'] }\);
const drive = google.drive\({ version: 'v3', auth }\);

const renames = [
  { id: '1nvNUM_gEMcHrkvcmUOp14HGAARomn1SG', name: 'Archive - Slack Conversation Log Feb 21 2026' },
  { id: '1toa7HE20qi1FnSt1uZG0UqQfARfadA4D', name: 'Archive - Studio88 Master Context Feb 4 2026' },
  { id: '1PKPtHWXK32L-a5k5QNsqjJC9KkCQub3cd7uxQeiYcTY', name: 'Archive - Conversation Log Feb 20 2026' },
];

async function main\(\) {
  for \(const f of renames\) {
    await drive.files.update\({ fileId: f.id, requestBody: { name: f.name } }\);
    console.log\('Renamed:', f.name\);
  }
}
main\(\).catch\(console.error\);
